dashboard.definition:
{
	"visualizations": {
		"viz_deployment_health": {
			"type": "splunk.singlevalue",
			"options": {
				"majorValue": "> primary | seriesByName('health_score') | lastPoint()",
				"numberPrecision": 0,
				"unit": "%",
				"majorColor": "> majorValue | rangeValue(healthColorConfig)",
				"healthColorConfig": [
					{
						"value": 0,
						"to": 70,
						"color": "#D41F1F"
					},
					{
						"value": 70,
						"to": 95,
						"color": "#F5A800"
					},
					{
						"value": 95,
						"color": "#118832"
					}
				]
			},
			"dataSources": {
				"primary": "ds_job_health"
			},
			"title": "Job Completion Rate",
			"description": "Overall health based on replicas and pod status"
		},
		"viz_desired_replicas": {
			"type": "splunk.singlevalue",
			"options": {
				"majorValue": "> sparklineValues | lastPoint()",
				"numberPrecision": 0,
				"unit": "Desired",
				"trendValue": "> sparklineValues | delta(-2)",
				"sparklineValues": "> primary | seriesByName('desired_successful')"
			},
			"dataSources": {
				"primary": "ds_replica_status"
			},
			"title": "Target Completions"
		},
		"viz_ready_replicas": {
			"type": "splunk.singlevalue",
			"options": {
				"majorValue": "> sparklineValues | lastPoint()",
				"numberPrecision": 0,
				"unit": "Successful",
				"majorColor": "#118832",
				"trendValue": "> sparklineValues | delta(-2)",
				"sparklineValues": "> primary | seriesByName('successful')"
			},
			"dataSources": {
				"primary": "ds_replica_status"
			},
			"title": "Successful"
		},
		"viz_available_replicas": {
			"type": "splunk.singlevalue",
			"options": {
				"majorValue": "> sparklineValues | lastPoint()",
				"numberPrecision": 0,
				"unit": "Active",
				"trendValue": "> sparklineValues | delta(-2)",
				"sparklineValues": "> primary | seriesByName('active')"
			},
			"dataSources": {
				"primary": "ds_replica_status"
			},
			"title": "Active Pods"
		},
		"viz_unavailable_replicas": {
			"type": "splunk.singlevalue",
			"options": {
				"majorValue": "> sparklineValues | lastPoint()",
				"numberPrecision": 0,
				"unit": "Failed",
				"majorColor": "> majorValue | rangeValue(unavailableColorConfig)",
				"unavailableColorConfig": [
					{
						"value": 0,
						"to": 1,
						"color": "#118832"
					},
					{
						"value": 1,
						"color": "#D41F1F"
					}
				],
				"trendValue": "> sparklineValues | delta(-2)",
				"sparklineValues": "> primary | seriesByName('failed')"
			},
			"dataSources": {
				"primary": "ds_replica_status"
			},
			"title": "Failed"
		},
		"viz_total_restarts": {
			"type": "splunk.singlevalue",
			"options": {
				"majorValue": "> sparklineValues | lastPoint()",
				"sparklineValues": "> primary | seriesByName('total_restarts')",
				"numberPrecision": 0,
				"unit": "Restarts",
				"majorColor": "> majorValue | rangeValue(restartColorConfig)",
				"restartColorConfig": [
					{
						"value": 0,
						"to": 5,
						"color": "#118832"
					},
					{
						"value": 5,
						"to": 20,
						"color": "#F5A800"
					},
					{
						"value": 20,
						"color": "#D41F1F"
					}
				]
			},
			"dataSources": {
				"primary": "ds_total_restarts"
			},
			"title": "Total Pod Restarts"
		},
		"viz_avg_cpu_usage": {
			"type": "splunk.singlevalue",
			"options": {
				"majorValue": "> sparklineValues | lastPoint()",
				"sparklineValues": "> primary | seriesByName('Avg_CPU_Core_Usage')",
				"numberPrecision": 1,
				"unit": "c",
				"trendValue": "> sparklineValues | delta(-2)"
			},
			"dataSources": {
				"primary": "ds_avg_cpu"
			},
			"title": "Avg CPU Cores Usage"
		},
		"viz_avg_memory_usage": {
			"type": "splunk.singlevalue",
			"options": {
				"majorValue": "> sparklineValues | lastPoint()",
				"sparklineValues": "> primary | seriesByName('avg_memory_mb')",
				"numberPrecision": 0,
				"unit": "MB"
			},
			"dataSources": {
				"primary": "ds_avg_memory"
			},
			"title": "Avg Memory Usage"
		},
		"viz_replica_timeline": {
			"type": "splunk.line",
			"options": {
				"xField": "_time",
				"legendDisplay": "bottom",
				"seriesColorsByField": {
					"desired": "#1E93C6",
					"successful": "#118832",
					"active": "#f8be44",
					"failed": "#dc4e41"
				}
			},
			"dataSources": {
				"primary": "ds_replica_timeline"
			},
			"title": "Replica Status Over Time",
			"description": "Desired vs Ready vs Available replicas"
		},
		"viz_cpu_per_pod": {
			"type": "splunk.column",
			"options": {},
			"dataSources": {
				"primary": "ds_cpu_per_pod"
			},
			"title": "CPU Usage per Pod (%)",
			"description": "Individual pod CPU utilization",
			"context": {},
			"containerOptions": {},
			"showProgressBar": false,
			"showLastUpdated": false
		},
		"viz_memory_per_pod": {
			"type": "splunk.line",
			"options": {
				"xField": "_time",
				"legendDisplay": "right",
				"legendTruncation": "ellipsisEnd",
				"nullValueDisplay": "connect"
			},
			"dataSources": {
				"primary": "ds_memory_per_pod"
			},
			"title": "Memory Usage per Pod (MB)",
			"description": "Individual pod memory consumption"
		},
		"viz_cpu_requests_vs_usage": {
			"type": "splunk.column",
			"options": {
				"xField": "pod",
				"legendDisplay": "bottom",
				"seriesColorsByField": {
					"cpu_request": "#1E93C6",
					"cpu_core_usage": "#F5A800"
				},
				"stackMode": "stacked"
			},
			"dataSources": {
				"primary": "ds_cpu_requests_vs_usage"
			},
			"title": "CPU: Requests vs Actual Usage",
			"description": "Resource allocation efficiency"
		},
		"viz_memory_requests_vs_usage": {
			"type": "splunk.column",
			"options": {
				"xField": "pod",
				"legendDisplay": "bottom",
				"seriesColorsByField": {
					"mem_request": "#1E93C6",
					"mem_usage_mbytes": "#F5A800"
				},
				"stackMode": "stacked",
				"y": "> primary | frameBySeriesNames('mem_request','_timediff','mem_usage_mbytes')"
			},
			"dataSources": {
				"primary": "ds_memory_requests_vs_usage"
			},
			"title": "Memory: Requests vs Actual Usage (MB)",
			"description": "Resource allocation efficiency"
		},
		"viz_pod_restart_counts": {
			"type": "splunk.column",
			"options": {
				"xField": "pod",
				"yField": "restart_count",
				"legendDisplay": "off",
				"seriesColors": [
					"#D41F1F"
				]
			},
			"dataSources": {
				"primary": "ds_pod_restarts"
			},
			"title": "Pod Restart Counts",
			"description": "Identify crashlooping pods"
		},
		"viz_pod_status_table": {
			"type": "splunk.table",
			"options": {
				"backgroundColor": "> table | seriesByName('Status') | matchValue(statusColorMap)",
				"statusColorMap": {
					"Running": "#118832",
					"Pending": "#F5A800",
					"Failed": "#D41F1F",
					"Unknown": "#999999"
				},
				"tableFormat": {
					"align": "left"
				},
				"columnFormat": {
					"Node": {
						"width": 157
					},
					"Pod": {
						"width": 155
					},
					"Restarts": {
						"data": "> table | seriesByName(\"Restarts\") | formatByType(RestartsColumnFormatEditorConfig)",
						"align": "auto",
						"headerAlign": "auto",
						"textOverflow": "break-word",
						"rowColors": "> table | seriesByName('Restarts') | pick(RestartsRowColorsEditorConfig)",
						"rowBackgroundColors": "> table | seriesByName(\"Restarts\") | rangeValue(RestartsRowBackgroundColorsEditorConfig)"
					},
					"Status": {
						"data": "> table | seriesByName(\"Status\") | formatByType(StatusColumnFormatEditorConfig)",
						"align": "auto",
						"headerAlign": "auto",
						"textOverflow": "break-word",
						"rowColors": "> table | seriesByName('Status') | pick(StatusRowColorsEditorConfig)",
						"rowBackgroundColors": "> table | seriesByName(\"Status\") | matchValue(StatusRowBackgroundColorsEditorConfig)"
					}
				}
			},
			"dataSources": {
				"primary": "ds_pod_status_table"
			},
			"title": "Pod Details",
			"description": "Current status of all pods in deployment",
			"context": {
				"RestartsColumnFormatEditorConfig": {
					"number": {
						"thousandSeparated": false,
						"unitPosition": "after"
					}
				},
				"StatusColumnFormatEditorConfig": {
					"string": {
						"unitPosition": "after"
					}
				},
				"RestartsRowColorsEditorConfig": [
					"#ffffff"
				],
				"RestartsRowBackgroundColorsEditorConfig": [
					{
						"value": "#118832",
						"to": 2
					},
					{
						"value": "#669922",
						"from": 2,
						"to": 3
					},
					{
						"value": "#CBA700",
						"from": 3,
						"to": 5
					},
					{
						"value": "#D94E17",
						"from": 5,
						"to": 7
					},
					{
						"value": "#D41F1F",
						"from": 7
					}
				],
				"StatusRowColorsEditorConfig": [
					"#ffffff"
				],
				"StatusRowBackgroundColorsEditorConfig": [
					{
						"match": "Failed",
						"value": "#D41F1F"
					},
					{
						"match": "Pending",
						"value": "#D97A0D"
					},
					{
						"match": "Running",
						"value": "#9D9F0D"
					},
					{
						"match": "Succeeded",
						"value": "#118832"
					}
				]
			}
		},
		"viz_resource_allocation": {
			"type": "splunk.table",
			"dataSources": {
				"primary": "ds_resource_allocation"
			},
			"title": "Resource Allocation Summary",
			"description": "Total requests, limits, and usage",
			"options": {
				"tableFormat": {
					"align": "left"
				},
				"showInternalFields": false
			}
		},
		"viz_deployment_events": {
			"type": "splunk.table",
			"options": {
				"backgroundColor": "> table | seriesByName('Type') | matchValue(eventColorMap)",
				"eventColorMap": {
					"Warning": "#F5A800",
					"Error": "#D41F1F",
					"Normal": "#FFFFFF"
				},
				"showInternalFields": false
			},
			"dataSources": {
				"primary": "ds_job_events"
			},
			"title": "Recent Job Events",
			"description": "Last 20 events related to Jobs"
		},
		"viz_pod_age": {
			"type": "splunk.table",
			"dataSources": {
				"primary": "ds_pod_age"
			},
			"title": "Pod Age Analysis",
			"description": "How long pods have been running"
		},
		"viz_network_io": {
			"type": "splunk.line",
			"options": {
				"xField": "_time",
				"legendDisplay": "bottom",
				"seriesColorsByField": {
					"rx_mb": "#1E93C6",
					"tx_mb": "#F5A800"
				},
				"nullValueDisplay": "connect"
			},
			"dataSources": {
				"primary": "ds_network_io"
			},
			"title": "Network I/O (MB/s)",
			"description": "Aggregate network traffic for all pods"
		},
		"viz_container_status": {
			"type": "splunk.table",
			"dataSources": {
				"primary": "ds_container_status"
			},
			"title": "Container Status by Pod",
			"description": "Individual container health within pods"
		},
		"viz_job_history": {
			"type": "splunk.table",
			"dataSources": {
				"primary": "ds_job_history"
			},
			"title": "Job Execution History",
			"description": "Recent job runs with completion status",
			"options": {
				"showInternalFields": false,
				"tableFormat": {
					"align": "left"
				}
			}
		}
	},
	"dataSources": {
		"ds_cluster_list": {
			"type": "ds.search",
			"options": {
				"query": "| mcatalog values(k8s.cluster.name) as cluster WHERE index=$index_token$ | mvexpand cluster | rename cluster as label | eval value=label",
				"queryParameters": {
					"earliest": "$global_time.earliest$",
					"latest": "$global_time.latest$"
				}
			},
			"name": "Cluster List"
		},
		"ds_namespace_list": {
			"type": "ds.search",
			"options": {
				"query": "| mcatalog values(k8s.namespace.name) as namespace WHERE index=$index_token$ | mvexpand namespace | rename namespace as label | eval value=label",
				"queryParameters": {
					"earliest": "$global_time.earliest$",
					"latest": "$global_time.latest$"
				}
			},
			"name": "Namespace List"
		},
		"ds_replica_status": {
			"type": "ds.search",
			"options": {
				"query": "| mstats latest(_value) as value WHERE index=$index_token$ (metric_name=k8s.job.desired_successful_pods OR metric_name=k8s.job.successful_pods OR metric_name=k8s.job.active_pods OR metric_name=k8s.job.failed_pods) k8s.cluster.name=$cluster_token$ k8s.namespace.name=$namespace_token$ (k8s.job.name=$job_token$ OR k8s.cronjob.name=$job_token$) by metric_name | eval desired=if(match(metric_name, \"job.desired\"), value, null()), available=if(match(metric_name, \"job.successful\"), value, null()), ready=if(match(metric_name, \"active\"), value, null()), unavailable=if(match(metric_name, \"failed\"), value, null()) | stats sum(desired) as desired_successful, sum(available) as successful, sum(ready) as active, sum(unavailable) as failed | fillnull value=0",
				"queryParameters": {
					"earliest": "$global_time.earliest$",
					"latest": "$global_time.latest$"
				}
			},
			"name": "Replica Status"
		},
		"ds_total_restarts": {
			"type": "ds.search",
			"options": {
				"query": "| mstats sum(_value) as total_restarts WHERE index=$index_token$ metric_name=k8s.container.restarts k8s.cluster.name=$cluster_token$ k8s.namespace.name=$namespace_token$ (k8s.job.name=$job_token$ OR k8s.cronjob.name=$job_token$) span=5m",
				"queryParameters": {
					"earliest": "$global_time.earliest$",
					"latest": "$global_time.latest$"
				}
			},
			"name": "Total Restarts"
		},
		"ds_avg_cpu": {
			"type": "ds.search",
			"options": {
				"query": "| mstats p90(_value) as cpu_core_usage WHERE index=$index_token$ metric_name=container.cpu.usage k8s.cluster.name=$cluster_token$ k8s.namespace.name=$namespace_token$ by k8s.pod.name span=2m\n| join type=left k8s.pod.name \n    [| mstats latest(k8s.pod.phase) as pod_phase WHERE index=$index_token$ k8s.namespace.name=$namespace_token$ k8s.cluster.name=$cluster_token$\n    by k8s.pod.name, k8s.namespace.name, k8s.node.name,\n       k8s.deployment.name, k8s.daemonset.name, k8s.statefulset.name,\n       k8s.replicaset.name, k8s.job.name, k8s.cronjob.name\n     fillnull_value=\"NA\"\n| rename k8s.namespace.name as namespace , k8s.statefulset.name as statefulset, k8s.deployment.name as deployment, k8s.daemonset.name as daemonset, k8s.job.name as job, k8s.cronjob.name as cronjob, k8s.pod.name as pod, k8s.replicaset.name as replicaset, k8s.node.name as node\n| stats count by namespace, pod, deployment, daemonset, statefulset, replicaset, job, cronjob, node\n| eval workload_type=case(\n    cronjob!=\"NA\", \"Job/CronJob\",\n    job!=\"NA\", \"Job/CronJob\",\n    deployment!=\"NA\", \"Deployment\",\n    daemonset!=\"NA\", \"DaemonSet\",\n    statefulset!=\"NA\", \"StatefulSet\",\n    replicaset!=\"NA\", \"ReplicaSet\",\n    1=1, \"Standalone\"\n)\n| eval statefulset=nullif(statefulset, \"NA\"), deployment=nullif(deployment, \"NA\"), daemonset=nullif(daemonset,\"NA\"), replicaset=nullif(replicaset, \"NA\"), job=nullif(job,\"NA\"), cronjob=nullif(cronjob,\"NA\")\n| eval workload_name=coalesce(\n    cronjob, job, deployment,\n    daemonset, statefulset,\n    replicaset\n)\n| table namespace, workload_type, workload_name, pod, node\n| rename namespace as Namespace, workload_type as Workload-Type, workload_name as Workload-Name, pod as k8s.pod.name, node as Node]\n| search Workload-Type=\"*Job*\" Workload-Name=$job_token$\n| timechart latest(cpu_core_usage) as Avg_CPU_Core_Usage span=2m\n| eval Avg_CPU_Core_Usage=round(Avg_CPU_Core_Usage,3)\n| fillnull value=0",
				"queryParameters": {
					"earliest": "$global_time.earliest$",
					"latest": "$global_time.latest$"
				}
			},
			"name": "Average CPU"
		},
		"ds_avg_memory": {
			"type": "ds.search",
			"options": {
				"query": "| mstats avg(_value) as avg_memory_bytes WHERE index=$index_token$ metric_name=container.memory.usage k8s.cluster.name=$cluster_token$ k8s.namespace.name=$namespace_token$ by k8s.pod.name span=2m | eval avg_memory_mb=avg_memory_bytes/1048576\n| join type=left k8s.pod.name \n    [| mstats latest(k8s.pod.phase) as pod_phase WHERE index=$index_token$ k8s.namespace.name=$namespace_token$ k8s.cluster.name=$cluster_token$\n    by k8s.pod.name, k8s.namespace.name, k8s.node.name,\n       k8s.deployment.name, k8s.daemonset.name, k8s.statefulset.name,\n       k8s.replicaset.name, k8s.job.name, k8s.cronjob.name\n     fillnull_value=\"NA\"\n| rename k8s.namespace.name as namespace , k8s.statefulset.name as statefulset, k8s.deployment.name as deployment, k8s.daemonset.name as daemonset, k8s.job.name as job, k8s.cronjob.name as cronjob, k8s.pod.name as pod, k8s.replicaset.name as replicaset, k8s.node.name as node\n| stats count by namespace, pod, deployment, daemonset, statefulset, replicaset, job, cronjob, node\n| eval workload_type=case(\n    cronjob!=\"NA\", \"Job/CronJob\",\n    job!=\"NA\", \"Job/CronJob\",\n    deployment!=\"NA\", \"Deployment\",\n    daemonset!=\"NA\", \"DaemonSet\",\n    statefulset!=\"NA\", \"StatefulSet\",\n    replicaset!=\"NA\", \"ReplicaSet\",\n    1=1, \"Standalone\"\n)\n| eval statefulset=nullif(statefulset, \"NA\"), deployment=nullif(deployment, \"NA\"), daemonset=nullif(daemonset,\"NA\"), replicaset=nullif(replicaset, \"NA\"), job=nullif(job,\"NA\"), cronjob=nullif(cronjob,\"NA\")\n| eval workload_name=coalesce(\n    cronjob, job, deployment,\n    daemonset, statefulset,\n    replicaset\n)\n| table namespace, workload_type, workload_name, pod, node\n| rename namespace as Namespace, workload_type as Workload-Type, workload_name as Workload-Name, pod as k8s.pod.name, node as Node]\n| search Workload-Type=\"*Job*\" Workload-Name=$job_token$\n| fillnull value=0\n| timechart avg(avg_memory_mb) as Avg_Memory_Usage(MB) span=2m",
				"queryParameters": {
					"earliest": "$global_time.earliest$",
					"latest": "$global_time.latest$"
				}
			},
			"name": "Average Memory"
		},
		"ds_replica_timeline": {
			"type": "ds.search",
			"options": {
				"query": "| mstats latest(_value) as value WHERE index=$index_token$ (metric_name=k8s.job.desired_successful_pods OR metric_name=k8s.job.successful_pods OR metric_name=k8s.job.active_pods OR metric_name=k8s.job.failed_pods) k8s.cluster.name=$cluster_token$ k8s.namespace.name=$namespace_token$ (k8s.job.name=$job_token$ OR k8s.cronjob.name=$job_token$) span=5m by metric_name | eval desired=if(match(metric_name, \"job.desired\"), value, null()), successful=if(match(metric_name, \"job.successful\"), value, null()), active=if(match(metric_name, \"active\"), value, null()),failed=if(match(metric_name, \"failed\"), value, null()) | stats sum(desired) as desired, sum(successful) as successful, sum(active) as active, sum(failed) as failed by _time",
				"queryParameters": {
					"earliest": "$global_time.earliest$",
					"latest": "$global_time.latest$"
				}
			},
			"name": "Replica Timeline"
		},
		"ds_cpu_per_pod": {
			"type": "ds.search",
			"options": {
				"query": "| mstats p90(_value) as cpu_core_usage WHERE index=$index_token$ metric_name=container.cpu.usage k8s.cluster.name=$cluster_token$ k8s.namespace.name=$namespace_token$ by k8s.pod.name span=5m\n| join type=left k8s.pod.name \n    [| mstats latest(k8s.pod.phase) as pod_phase WHERE index=$index_token$ k8s.namespace.name=$namespace_token$ k8s.cluster.name=$cluster_token$\n    by k8s.pod.name, k8s.namespace.name, k8s.node.name,\n       k8s.deployment.name, k8s.daemonset.name, k8s.statefulset.name,\n       k8s.replicaset.name, k8s.job.name, k8s.cronjob.name\n     fillnull_value=\"NA\"\n| rename k8s.namespace.name as namespace , k8s.statefulset.name as statefulset, k8s.deployment.name as deployment, k8s.daemonset.name as daemonset, k8s.job.name as job, k8s.cronjob.name as cronjob, k8s.pod.name as pod, k8s.replicaset.name as replicaset, k8s.node.name as node\n| stats count by namespace, pod, deployment, daemonset, statefulset, replicaset, job, cronjob, node\n| eval workload_type=case(\n    cronjob!=\"NA\", \"Job/CronJob\",\n    job!=\"NA\", \"Job/CronJob\",\n    deployment!=\"NA\", \"Deployment\",\n    daemonset!=\"NA\", \"DaemonSet\",\n    statefulset!=\"NA\", \"StatefulSet\",\n    replicaset!=\"NA\", \"ReplicaSet\",\n    1=1, \"Standalone\"\n)\n| eval statefulset=nullif(statefulset, \"NA\"), deployment=nullif(deployment, \"NA\"), daemonset=nullif(daemonset,\"NA\"), replicaset=nullif(replicaset, \"NA\"), job=nullif(job,\"NA\"), cronjob=nullif(cronjob,\"NA\")\n| eval workload_name=coalesce(\n    cronjob, job, deployment,\n    daemonset, statefulset,\n    replicaset\n)\n| table namespace, workload_type, workload_name, pod, node\n| rename namespace as Namespace, workload_type as Workload-Type, workload_name as Workload-Name, pod as k8s.pod.name, node as Node]\n| search Workload-Type=\"*Job*\" Workload-Name=$job_token$\n| timechart avg(cpu_core_usage) as Avg_CPU_Core_Usage by k8s.pod.name",
