		"ds_cpu_requests_vs_usage": {
			"type": "ds.search",
			"options": {
				"query": "| mstats p90(_value) as cpu_core_usage WHERE index=$index_token$ metric_name=container.cpu.usage k8s.cluster.name=$cluster_token$ k8s.namespace.name=$namespace_token$ by k8s.pod.name\n| join type=left k8s.pod.name \n    [| mstats latest(k8s.pod.phase) as pod_phase WHERE index=$index_token$ k8s.namespace.name=$namespace_token$ k8s.cluster.name=$cluster_token$\n    by k8s.pod.name, k8s.namespace.name, k8s.node.name,\n       k8s.deployment.name, k8s.daemonset.name, k8s.statefulset.name,\n       k8s.replicaset.name, k8s.job.name, k8s.cronjob.name\n     fillnull_value=\"NA\"\n| rename k8s.namespace.name as namespace , k8s.statefulset.name as statefulset, k8s.deployment.name as deployment, k8s.daemonset.name as daemonset, k8s.job.name as job, k8s.cronjob.name as cronjob, k8s.pod.name as pod, k8s.replicaset.name as replicaset, k8s.node.name as node\n| stats count by namespace, pod, deployment, daemonset, statefulset, replicaset, job, cronjob, node\n| eval workload_type=case(\n    cronjob!=\"NA\", \"Job/CronJob\",\n    job!=\"NA\", \"Job/CronJob\",\n    deployment!=\"NA\", \"Deployment\",\n    daemonset!=\"NA\", \"DaemonSet\",\n    statefulset!=\"NA\", \"StatefulSet\",\n    replicaset!=\"NA\", \"ReplicaSet\",\n    1=1, \"Standalone\"\n)\n| eval statefulset=nullif(statefulset, \"NA\"), deployment=nullif(deployment, \"NA\"), daemonset=nullif(daemonset,\"NA\"), replicaset=nullif(replicaset, \"NA\"), job=nullif(job,\"NA\"), cronjob=nullif(cronjob,\"NA\")\n| eval workload_name=coalesce(\n    cronjob, job, deployment,\n    daemonset, statefulset,\n    replicaset\n)\n| table namespace, workload_type, workload_name, pod, node\n| rename namespace as Namespace, workload_type as Workload-Type, workload_name as Workload-Name, pod as k8s.pod.name, node as Node]\n| search Workload-Type=\"*Job*\" Workload-Name=$job_token$\n| join type=outer k8s.pod.name \n    [| mstats latest(_value) as value WHERE index=$index_token$ ( metric_name=k8s.container.cpu_request) k8s.cluster.name=$cluster_token$ k8s.namespace.name=$namespace_token$  by k8s.pod.name, metric_name\n| eval cpu_request=if(match(metric_name, \"request\"), value, null()) | stats avg(cpu_request) as cpu_request by k8s.pod.name| eval cpu_request=round(cpu_request, 3)]\n| fillnull value=0 cpu_request| rename k8s.pod.name as pod\n| fields pod, cpu_request, cpu_core_usage",
				"queryParameters": {
					"earliest": "$global_time.earliest$",
					"latest": "$global_time.latest$"
				}
			},
			"name": "CPU Requests vs Usage"
		},
		"ds_memory_requests_vs_usage": {
			"type": "ds.search",
			"options": {
				"query": "| mstats p90(_value) as mem_usage_bytes WHERE index=$index_token$ metric_name=k8s.pod.memory.usage k8s.cluster.name=$cluster_token$ k8s.namespace.name=$namespace_token$ by k8s.pod.name\n| join type=left k8s.pod.name \n    [| mstats latest(k8s.pod.phase) as pod_phase WHERE index=$index_token$ k8s.namespace.name=$namespace_token$ k8s.cluster.name=$cluster_token$\n    by k8s.pod.name, k8s.namespace.name, k8s.node.name,\n       k8s.deployment.name, k8s.daemonset.name, k8s.statefulset.name,\n       k8s.replicaset.name, k8s.job.name, k8s.cronjob.name\n     fillnull_value=\"NA\"\n| rename k8s.namespace.name as namespace , k8s.statefulset.name as statefulset, k8s.deployment.name as deployment, k8s.daemonset.name as daemonset, k8s.job.name as job, k8s.cronjob.name as cronjob, k8s.pod.name as pod, k8s.replicaset.name as replicaset, k8s.node.name as node\n| stats count by namespace, pod, deployment, daemonset, statefulset, replicaset, job, cronjob, node\n| eval workload_type=case(\n    cronjob!=\"NA\", \"Job/CronJob\",\n    job!=\"NA\", \"Job/CronJob\",\n    deployment!=\"NA\", \"Deployment\",\n    daemonset!=\"NA\", \"DaemonSet\",\n    statefulset!=\"NA\", \"StatefulSet\",\n    replicaset!=\"NA\", \"ReplicaSet\",\n    1=1, \"Standalone\"\n)\n| eval statefulset=nullif(statefulset, \"NA\"), deployment=nullif(deployment, \"NA\"), daemonset=nullif(daemonset,\"NA\"), replicaset=nullif(replicaset, \"NA\"), job=nullif(job,\"NA\"), cronjob=nullif(cronjob,\"NA\")\n| eval workload_name=coalesce(\n    cronjob, job, deployment,\n    daemonset, statefulset,\n    replicaset\n)\n| table namespace, workload_type, workload_name, pod, node\n| rename namespace as Namespace, workload_type as Workload-Type, workload_name as Workload-Name, pod as k8s.pod.name, node as Node]\n| search Workload-Type=\"*Job*\" Workload-Name=$job_token$\n| join type=outer k8s.pod.name \n    [| mstats latest(_value) as value WHERE index=$index_token$ ( metric_name=k8s.container.memory_request) k8s.cluster.name=$cluster_token$ k8s.namespace.name=$namespace_token$  by k8s.pod.name, metric_name\n| eval mem_request=if(match(metric_name, \"request\"), value, null()) | stats avg(mem_request) as mem_request by k8s.pod.name| eval cpu_request=round(mem_request, 3)]\n| fillnull value=0 mem_request\n| rename k8s.pod.name as pod\n| fields pod, mem_request, mem_usage_bytes\n| eval mem_request=round(mem_request/1048576,2), mem_usage_mbytes=round(mem_usage_bytes/1048576,2)",
				"queryParameters": {
					"earliest": "$global_time.earliest$",
					"latest": "$global_time.latest$"
				}
			},
			"name": "Memory Requests vs Usage"
		},
		"ds_pod_restarts": {
			"type": "ds.search",
			"options": {
				"query": "| mstats sum(_value) as restart_count WHERE index=$index_token$ metric_name=k8s.container.restarts k8s.cluster.name=$cluster_token$ k8s.namespace.name=$namespace_token$ k8s.job.name=$job_token$ by k8s.pod.name | rename k8s.pod.name as pod | sort -restart_count",
				"queryParameters": {
					"earliest": "$global_time.earliest$",
					"latest": "$global_time.latest$"
				}
			},
			"name": "Pod Restarts"
		},
		"ds_pod_status_table": {
			"type": "ds.search",
			"options": {
				"query": "| mstats latest(_value) as phase WHERE index=$index_token$ metric_name=k8s.pod.phase k8s.cluster.name=$cluster_token$ k8s.namespace.name=$namespace_token$ k8s.job.name=$job_token$ by k8s.pod.name, k8s.node.name | eval Status=case(phase==1 OR phase==\"Pending\", \"Pending\", phase==2 OR phase==\"Running\", \"Running\", phase==4 OR phase==\"Failed\", \"Failed\", phase==3 OR phase==\"Succeeded\", \"Succeeded\", 1==1, \"Unknown\") | join type=left k8s.pod.name [| mstats p90(_value) as cpu WHERE index=$index_token$ metric_name=k8s.pod.cpu.usage k8s.cluster.name=$cluster_token$ k8s.namespace.name=$namespace_token$ by k8s.pod.name] | join type=left k8s.pod.name [| mstats avg(_value) as mem_bytes WHERE index=$index_token$ metric_name=k8s.pod.memory.usage k8s.cluster.name=$cluster_token$ k8s.namespace.name=$namespace_token$  by k8s.pod.name | eval mem_mb=mem_bytes/1048576] | join type=left k8s.pod.name [| mstats sum(_value) as restarts WHERE index=$index_token$ metric_name=k8s.container.restarts k8s.cluster.name=$cluster_token$ k8s.namespace.name=$namespace_token$ by k8s.pod.name] | fillnull value=0 cpu, mem_mb, restarts | eval \"CPU cores\"=round(cpu, 3), \"Memory (MB)\"=round(mem_mb, 2), Restarts=round(restarts,0) | rename k8s.pod.name as Pod, k8s.node.name as Node | table Pod, Node, Status, \"CPU cores\", \"Memory (MB)\", Restarts | sort Pod",
				"queryParameters": {
					"earliest": "$global_time.earliest$",
					"latest": "$global_time.latest$"
				}
			},
			"name": "Pod Status Table"
		},
		"ds_resource_allocation": {
			"type": "ds.search",
			"options": {
				"query": "| mstats latest(k8s.pod.phase) as pod_phase WHERE index=$index_token$ k8s.namespace.name=$namespace_token$ k8s.cluster.name=$cluster_token$\n    by k8s.pod.name, k8s.namespace.name, k8s.node.name,\n       k8s.deployment.name, k8s.daemonset.name, k8s.statefulset.name,\n       k8s.replicaset.name, k8s.job.name, k8s.cronjob.name\n     fillnull_value=\"NA\"\n| rename k8s.namespace.name as namespace , k8s.statefulset.name as statefulset, k8s.deployment.name as deployment, k8s.daemonset.name as daemonset, k8s.job.name as job, k8s.cronjob.name as cronjob, k8s.pod.name as pod, k8s.replicaset.name as replicaset, k8s.node.name as node\n| stats count by namespace, pod, deployment, daemonset, statefulset, replicaset, job, cronjob, node\n| eval workload_type=case(\n    cronjob!=\"NA\", \"Job/CronJob\",\n    job!=\"NA\", \"Job/CronJob\",\n    deployment!=\"NA\", \"Deployment\",\n    daemonset!=\"NA\", \"DaemonSet\",\n    statefulset!=\"NA\", \"StatefulSet\",\n    replicaset!=\"NA\", \"ReplicaSet\",\n    1=1, \"Standalone\"\n)\n| eval statefulset=nullif(statefulset, \"NA\"), deployment=nullif(deployment, \"NA\"), daemonset=nullif(daemonset,\"NA\"), replicaset=nullif(replicaset, \"NA\"), job=nullif(job,\"NA\"), cronjob=nullif(cronjob,\"NA\")\n| eval workload_name=coalesce(\n    cronjob, job, deployment,\n    daemonset, statefulset,\n    replicaset\n)\n| table namespace, workload_type, workload_name, pod, node\n| rename namespace as Namespace, workload_type as Workload-Type, workload_name as Workload-Name, pod as Pod, node as Node\n| search Workload-Type=\"*Job*\"\n| fields  - \"Workload-Type\", Node\n| join type=outer Pod \n    [| mstats latest(_value) as value WHERE index=$index_token$ (metric_name=k8s.pod.cpu.request OR metric_name=k8s.container.cpu_request OR metric_name=k8s.container.cpu_limit OR metric_name=k8s.pod.memory.request OR metric_name=k8s.container.memory_request OR metric_name=k8s.container.memory_limit OR metric_name=container.cpu.usage OR metric_name=container.memory.usage) k8s.cluster.name=$cluster_token$ k8s.namespace.name=$namespace_token$  by  k8s.namespace.name, k8s.pod.name, metric_name\n| eval cpu_limit=if(match(metric_name, \"cpu_limit\"), value, null()), \n       cpu_request=if(match(metric_name, \"cpu_request\"), value, null()), \n       mem_limit=if(match(metric_name, \"memory_limit\"), value/1073741824, null()), \n       mem_request=if(match(metric_name, \"memory_request\"), value/1073741824, null()), \n       cpu_usage=if(match(metric_name, \"cpu.usage\"), value, null()), \n       mem_usage=if(match(metric_name, \"memory.usage\"), value/1073741824, null())\n| stats avg(cpu_limit) as cpu_limit, avg(cpu_request) as cpu_req, avg(mem_limit) as mem_limit, avg(mem_request) as mem_req, avg(cpu_usage) as cpu_use, avg(mem_usage) as mem_use by k8s.namespace.name , k8s.pod.name\n| eval \"CPU Request\"=round(cpu_req, 2),\"CPU Limit\"=round(cpu_limit, 2), \"CPU Usage\"=round(cpu_use, 2), \"Memory Request (GB)\"=round(mem_req, 2), \"Memory Limit (GB)\"=round(mem_limit, 2), \"Memory Usage (GB)\"=round(mem_use, 2)\n| rename k8s.pod.name as Pod, k8s.namespace.name as Namespace \n| table Pod, Namespace, \"CPU Request\", \"CPU Usage\",\"CPU Limit\", \"Memory Request (GB)\",\"Memory Usage (GB)\", \"Memory Limit (GB)\" \n| sort -\"CPU Usage\"\n| rename \"CPU Usage\" as \"CPU Usage (cores)\", \"CPU Request\" as \"CPU Request (cores)\", \"CPU Limit\" as \"CPU Limit (cores)\"\n| fillnull value=0 \"CPU Request (cores)\", \"CPU Limit (cores)\",\"Memory Request (GB)\", \"Memory Limit (GB)\"]\n| search \"Workload-Name\"=$job_token$",
				"queryParameters": {
					"earliest": "$global_time.earliest$",
					"latest": "$global_time.latest$"
				}
			},
			"name": "Resource Allocation"
		},
		"ds_pod_age": {
			"type": "ds.search",
			"options": {
				"query": "| mstats latest(_value) as phase WHERE index=$index_token$ metric_name=k8s.pod.phase k8s.cluster.name=$cluster_token$ k8s.namespace.name=$namespace_token$ k8s.job.name=$job_token$ by k8s.pod.name, k8s.job.name, k8s.namespace.name, k8s.pod.start_time |rename k8s.pod.start_time as start_time, k8s.pod.name as Pod, k8s.namespace.name as Namespace, k8s.job.name as Job\n| table Pod, start_time, Namespace, Job\n| eval current_time=now()\n| eval start_time_epoch=strptime(start_time, \"%Y-%m-%dT%H:%M:%SZ\")\n| eval age_seconds= current_time-start_time_epoch, age_hours=round(age_seconds/3600, 1), age_days=round(age_seconds/86400, 1)| eval \"Age\"=if(age_days>=1, age_days.\" days\", age_hours.\" hours\")| table Pod, Age | sort -age_seconds",
				"queryParameters": {
					"earliest": "$global_time.earliest$",
					"latest": "$global_time.latest$"
				}
			},
			"name": "Pod Age"
		},
		"ds_network_io": {
			"type": "ds.search",
			"options": {
				"query": "| mstats sum(_value) as bytes WHERE index=$index_token$ (metric_name=pod.network.io OR metric_name=k8s.pod.network.io) k8s.cluster.name=$cluster_token$ k8s.namespace.name=$namespace_token$  span=5m by k8s.pod.name, direction| eval direction=if(match(direction, \"transmit\"), \"tx_mb\", \"rx_mb\"), mb=bytes/1048576 \n| rename k8s.pod.name as Pod\n| join type=outer Pod \n    [| mstats latest(k8s.pod.phase) as pod_phase WHERE index=$index_token$  k8s.namespace.name=$namespace_token$ k8s.cluster.name=$cluster_token$ \n    by k8s.pod.name, k8s.namespace.name, k8s.node.name,\n       k8s.deployment.name, k8s.daemonset.name, k8s.statefulset.name,\n       k8s.replicaset.name, k8s.job.name, k8s.cronjob.name\n     fillnull_value=\"NA\"\n| rename k8s.namespace.name as namespace , k8s.statefulset.name as statefulset, k8s.deployment.name as deployment, k8s.daemonset.name as daemonset, k8s.job.name as job, k8s.cronjob.name as cronjob, k8s.pod.name as pod, k8s.replicaset.name as replicaset, k8s.node.name as node\n| stats count by namespace, pod, deployment, daemonset, statefulset, replicaset, job, cronjob, node\n| eval workload_type=case(\n    cronjob!=\"NA\", \"Job/CronJob\",\n    job!=\"NA\", \"Job/CronJob\",\n    deployment!=\"NA\", \"Deployment\",\n    daemonset!=\"NA\", \"DaemonSet\",\n    statefulset!=\"NA\", \"StatefulSet\",\n    replicaset!=\"NA\", \"ReplicaSet\",\n    1=1, \"Standalone\"\n)\n| eval statefulset=nullif(statefulset, \"NA\"), deployment=nullif(deployment, \"NA\"), daemonset=nullif(daemonset,\"NA\"), replicaset=nullif(replicaset, \"NA\"), job=nullif(job,\"NA\"), cronjob=nullif(cronjob,\"NA\")\n| eval workload_name=coalesce(\n    cronjob, job, deployment,\n    daemonset, statefulset,\n    replicaset\n)\n| table namespace, workload_type, workload_name, pod, node\n| rename namespace as Namespace, workload_type as Workload-Type, workload_name as Workload-Name, pod as Pod, node as Node\n| search Workload-Type=\"*Job*\"\n| table Pod, Workload-Type, Workload-Name]|search Workload-Name=$job_token$\n| timechart avg(mb) as NW_IO_MB by Workload-Name ",
				"queryParameters": {
					"earliest": "$global_time.earliest$",
					"latest": "$global_time.latest$"
				}
			},
			"name": "Network IO"
		},
		"ds_container_status": {
			"type": "ds.search",
			"options": {
				"query": "| mstats latest(_value) as ready WHERE index=$index_token$ metric_name=k8s.container.ready k8s.cluster.name=$cluster_token$ k8s.namespace.name=$namespace_token$ k8s.job.name=$job_token$ by k8s.pod.name, k8s.container.name | eval Status=if(ready==1, \"Ready\", \"Not Ready\") | rename k8s.pod.name as Pod, k8s.container.name as Container | table Pod, Container, Status | sort Pod, Container",
				"queryParameters": {
					"earliest": "$global_time.earliest$",
					"latest": "$global_time.latest$"
				}
			},
			"name": "Container Status"
		},
		"ds_job_list": {
			"type": "ds.search",
			"options": {
				"query": "| mcatalog values(k8s.job.name) as job WHERE index=$index_token$ k8s.namespace.name=$namespace_token$| mvexpand job | rename job as label | eval value=label",
				"queryParameters": {
					"earliest": "$global_time.earliest$",
					"latest": "$global_time.latest$"
				}
			},
			"name": "Job List"
		},
		"ds_job_health": {
			"type": "ds.search",
			"options": {
				"query": "| mstats latest(_value) as value WHERE index=$index_token$ (metric_name=k8s.job.successful_pods OR metric_name=k8s.job.desired_successful_pods) k8s.cluster.name=$cluster_token$ k8s.namespace.name=$namespace_token$ (k8s.job.name=$job_token$ OR k8s.cronjob.name=$job_token$) by metric_name | eval desired=if(match(metric_name, \"desired_successful\"), value, null()), available=if(match(metric_name, \"job.successful\"), value, null()) | stats sum(desired) as desired, sum(available) as available | eval health_score=if(desired>0, round((available/desired)*100, 0), 0)",
				"queryParameters": {
					"earliest": "$global_time.earliest$",
					"latest": "$global_time.latest$"
				}
			},
			"name": "Deployment Health"
		},
		"ds_job_events": {
			"type": "ds.search",
			"options": {
				"query": "index=$logs_index_token$ k8s.cluster.name=$cluster_token$ (source=*kube-events* OR sourcetype=kube:events)| head 100 | table _time,  k8s.event.reason,k8s.object.name,k8s.object.kind,k8s.namespace.name, _raw | rename _time as Time, reason as Reason, _raw as Message, k8s.object.name as \"Object\", k8s.object.kind as ObjectType, k8s.event.reason as \"Category\", k8s.namespace.name as Namespace | sort -Time\n| search Namespace=$namespace_token$\n| join type=outer Object\n    [| mstats latest(k8s.pod.phase) as pod_phase WHERE index=$index_token$ k8s.namespace.name=$namespace_token$ k8s.cluster.name=$cluster_token$\n    by k8s.pod.name, k8s.namespace.name, k8s.node.name,\n       k8s.deployment.name, k8s.daemonset.name, k8s.statefulset.name,\n       k8s.replicaset.name, k8s.job.name, k8s.cronjob.name\n     fillnull_value=\"NA\"\n| rename k8s.namespace.name as namespace , k8s.statefulset.name as statefulset, k8s.deployment.name as deployment, k8s.daemonset.name as daemonset, k8s.job.name as job, k8s.cronjob.name as cronjob, k8s.pod.name as pod, k8s.replicaset.name as replicaset, k8s.node.name as node\n| stats count by namespace, pod, deployment, daemonset, statefulset, replicaset, job, cronjob, node\n| eval workload_type=case(\n    cronjob!=\"NA\", \"Job/CronJob\",\n    job!=\"NA\", \"Job/CronJob\",\n    deployment!=\"NA\", \"Deployment\",\n    daemonset!=\"NA\", \"DaemonSet\",\n    statefulset!=\"NA\", \"StatefulSet\",\n    replicaset!=\"NA\", \"ReplicaSet\",\n    1=1, \"Standalone\"\n)\n| eval statefulset=nullif(statefulset, \"NA\"), deployment=nullif(deployment, \"NA\"), daemonset=nullif(daemonset,\"NA\"), replicaset=nullif(replicaset, \"NA\"), job=nullif(job,\"NA\"), cronjob=nullif(cronjob,\"NA\")\n| eval workload_name=coalesce(\n    cronjob, job, deployment,\n    daemonset, statefulset,\n    replicaset\n)\n| table namespace, workload_type, workload_name, pod, node\n| rename namespace as Namespace, workload_type as Workload-Type, workload_name as Workload-Name, pod as Object, node as Node]\n| search Workload-Type=\"*Job*\"\n| fields - Workload-Type\n| search Workload-Name=$job_token$| eval Time = strftime(Time, \"%Y-%m-%d %H:%M:%S.%3N\")",
				"queryParameters": {
					"earliest": "$global_time.earliest$",
					"latest": "$global_time.latest$"
				}
			},
			"name": "Deployment Events"
		},
		"ds_job_history": {
			"type": "ds.search",
			"options": {
				"query": "| mstats latest(_value) as value WHERE index=$index_token$ (metric_name=k8s.job.successful_pods OR metric_name=k8s.job.failed_pods OR metric_name=k8s.job.active_pods) k8s.cluster.name=$cluster_token$ k8s.namespace.name=$namespace_token$ (k8s.job.name=$job_token$ OR k8s.cronjob.name=$job_token$) span=1h by metric_name\n| eval successful=if(match(metric_name, \"successful\"), value, null()), failed=if(match(metric_name, \"failed\"), value, null()), active=if(match(metric_name, \"active\"), value, null()) \n| stats sum(successful) as Successful, sum(failed) as Failed, sum(active) as Active by _time \n| eval Status=case(Failed>0, \"Failed\", Successful>0, \"Success\", Active>0, \"Running\", 1==1, \"Unknown\") \n| rename _time as Time \n| table Time, Status, Successful, Failed, Active \n| sort -Time \n| head 20| eval Time = strftime(Time, \"%Y-%m-%d %H:%M:%S.%3N\")",
				"queryParameters": {
					"earliest": "$global_time.earliest$",
					"latest": "$global_time.latest$"
				}
			},
			"name": "Job History"
		},
		"ds_2Q8kpSOc": {
			"type": "ds.search",
			"options": {
				"query": "| inputlookup append=t k8s_metrics_indexes_dropdown_lookup.csv"
			},
			"name": "metrics_index_dropdown"
		},
		"ds_DjoZeC1x": {
			"type": "ds.search",
			"options": {
				"query": "| inputlookup append=t k8s_logs_events_indexes_dropdown_lookup.csv"
			},
			"name": "logs_index_dropdown"
		}
	},
	"defaults": {
		"dataSources": {
