			"context": {
				"formattedConfig": {
					"number": {
						"prefix": ""
					}
				},
				"formattedStatics": ">statics | formatByType(formattedConfig)",
				"statics": [],
				"label": ">primary | seriesByName(\"metrics_index_key\") | renameSeries(\"label\") | formatByType(formattedConfig)",
				"value": ">primary | seriesByName(\"metrics_index_value\") | renameSeries(\"value\") | formatByType(formattedConfig)"
			}
		},
		"input_job_selector": {
			"type": "input.dropdown",
			"options": {
				"defaultValue": "*",
				"token": "job_token"
			},
			"dataSources": {
				"primary": "ds_job_list"
			},
			"title": "Job/CronJob"
		},
		"input_1xZxG9Cr": {
			"options": {
				"items": ">frame(label, value) | prepend(formattedStatics) | objects()",
				"token": "logs_index_token",
				"selectFirstSearchResult": true
			},
			"title": "Event Logs Index",
			"type": "input.dropdown",
			"dataSources": {
				"primary": "ds_DjoZeC1x"
			},
			"context": {
				"formattedConfig": {
					"number": {
						"prefix": ""
					}
				},
				"formattedStatics": ">statics | formatByType(formattedConfig)",
				"statics": [],
				"label": ">primary | seriesByName(\"logs_index_key\") | renameSeries(\"label\") | formatByType(formattedConfig)",
				"value": ">primary | seriesByName(\"logs_index_value\") | renameSeries(\"value\") | formatByType(formattedConfig)"
			}
		}
	},
